package com.yhk.aistudyplanner.ai.service;
import com.yhk.aistudyplanner.ai.mapper.AiPlanningContextMapper;import com.yhk.aistudyplanner.ai.vo.AiPlanningContext;import org.springframework.stereotype.Service;import java.time.*;import java.util.List;
@Service public class AiPlanningContextService {private final AiPlanningContextMapper mapper;private final Clock clock;public AiPlanningContextService(AiPlanningContextMapper m,Clock c){mapper=m;clock=c;}public AiPlanningContext build(long userId,LocalDate planDate){LocalDate today=LocalDate.now(clock);LocalDateTime to=today.plusDays(1).atStartOfDay(),from=today.minusDays(6).atStartOfDay();var summary=mapper.summary(userId,from,to);if(summary==null)summary=new AiPlanningContext.StudySummaryContext(0,0,0);return new AiPlanningContext(mapper.subjects(userId),mapper.goals(userId),sanitize(mapper.tasks(userId,planDate,planDate.atStartOfDay())),summary,mapper.subjectStudy(userId,from,to),sanitizeRecords(mapper.records(userId)));}
 private List<AiPlanningContext.TaskContext> sanitize(List<AiPlanningContext.TaskContext> list){return list.stream().map(t->new AiPlanningContext.TaskContext(t.id(),t.subjectId(),t.subjectName(),t.subjectColor(),t.goalId(),t.goalTitle(),t.title(),cut(t.description(),300),t.priority(),t.status(),t.estimatedMinutes(),t.plannedDate(),t.dueAt())).toList();}
 private List<AiPlanningContext.RecordContext> sanitizeRecords(List<AiPlanningContext.RecordContext> list){return list.stream().map(r->new AiPlanningContext.RecordContext(r.subjectId(),r.subjectName(),r.taskId(),r.taskTitle(),r.startedAt(),r.durationMinutes(),cut(r.feedback(),300))).toList();}
 private String cut(String s,int max){return s==null?null:s.substring(0,Math.min(s.length(),max));}}
